function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = s.length;

    // 1. Count frequencies and record first appearance index for each vowel
    const freq = {};
    const firstIndex = {};

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            freq[char] = (freq[char] || 0) + 1;
            if (!(char in firstIndex)) {
                firstIndex[char] = i;
            }
        }
    }

    // 2. Prepare the list of unique vowels present in s, along with their data
    const uniqueVowels = [];
    for (const char of Object.keys(freq)) {
        uniqueVowels.push({
            char: char,
            count: freq[char],
            firstPos: firstIndex[char]
        });
    }

    // 3. Sort the vowels according to the rules:
    //    a) Decreasing order of frequency (count)
    //    b) If frequencies are equal, increasing order of first appearance position (firstPos)
    uniqueVowels.sort((v1, v2) => {
        // Primary sort: frequency (descending)
        if (v1.count !== v2.count) {
            return v2.count - v1.count;
        }
        // Secondary sort: first position (ascending)
        return v1.firstPos - v2.firstPos;
    });

    // 4. Construct the result string
    // We need to know the sequence of original vowel positions
    const vowelPositions = [];
    for (let i = 0; i < n; i++) {
        if (vowels.has(s[i])) {
            vowelPositions.push(i);
        }
    }

    // Create a map to hold the sorted vowels sequence
    const sortedVowelSequence = [];
    for (const v of uniqueVowels) {
        sortedVowelSequence.push(v.char.repeat(v.count));
    }
    const replacementVowels = sortedVowelSequence.join('');

    // Place the sorted vowels back into the original vowel positions
    const resultChars = Array(n);
    let replacementIndex = 0;

    for (let i = 0; i < n; i++) {
        if (vowels.has(s[i])) {
            // This position originally held a vowel, replace it with the next sorted vowel
            resultChars[i] = replacementVowels[replacementIndex];
            replacementIndex++;
        } else {
            // This position held a consonant, keep it as is
            resultChars[i] = s[i];
        }
    }

    return resultChars.join('');
}

