package main

import (
	"sort"
)

type vowelInfo struct {
	char    rune
	count   int
	firstPos int
}

func solve(s string) string {
	vowels := map[rune]bool{
		'a': true, 'e': true, 'i': true, 'o': true, 'u': true,
	}
	n := len(s)

	// 1. Count frequencies and record first appearance index for each vowel
	freq := make(map[rune]int)
	firstIndex := make(map[rune]int)

	for i, char := range s {
		if vowels[char] {
			freq[char]++
			if _, exists := firstIndex[char]; !exists {
				firstIndex[char] = i
			}
		}
	}

	// 2. Prepare the list of unique vowels present in s, along with their data
	var uniqueVowels []vowelInfo
	for char, count := range freq {
		uniqueVowels = append(uniqueVowels, vowelInfo{
			char:    char,
			count:   count,
			firstPos: firstIndex[char],
		})
	}

	// 3. Sort the vowels according to the rules:
	//    a) Decreasing order of frequency (count)
	//    b) If frequencies are equal, increasing order of first appearance position (firstPos)
	sort.Slice(uniqueVowels, func(i, j int) bool {
		v1 := uniqueVowels[i]
		v2 := uniqueVowels[j]

		// Primary sort: frequency (descending)
		if v1.count != v2.count {
			return v1.count > v2.count
		}
		// Secondary sort: first position (ascending)
		return v1.firstPos < v2.firstPos
	})

	// 4. Construct the result string
	result := make([]rune, n)
	copy(result, []rune(s)) // Start with the original string

	// Create a sequence of all sorted vowels to be placed back
	var sortedVowelSequence []rune
	for _, v := range uniqueVowels {
		for i := 0; i < v.count; i++ {
			sortedVowelSequence = append(sortedVowelSequence, v.char)
		}
	}

	// Place the sorted vowels back into the original vowel positions
	sortedVowelIndex := 0
	for i, char := range s {
		if vowels[char] {
			// This position originally held a vowel, replace it with the next sorted vowel
			result[i] = sortedVowelSequence[sortedVowelIndex]
			sortedVowelIndex++
		}
		// If it's a consonant, it remains as it was (since we copied s initially)
	}

	return string(result)
}
