			freq[char]++
			if _, exists := firstIndex[char]; !exists {
				firstIndex[char] = i
			}
			vowelPositions = append(vowelPositions, i)
		}
	}

	// 2. Prepare the list of unique vowels present in s, along with their data
	var uniqueVowels []vowelInfo
	for char, count := range freq {
		uniqueVowels = append(uniqueVowels, vowelInfo{
			char:     char,
			count:    count,
			firstPos: firstIndex[char],
		})
	}

